#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <cstdio>

std::string execute_command(const std::string& cmd) {
    std::string result = "";
    FILE* pipe = popen(cmd.c_str(), "r");
    if (!pipe) {
        return "ERROR: Could not run command.\n";
    }
    char buffer[128];
    while (fgets(buffer, sizeof(buffer), pipe) != NULL) {
        result += buffer;
    }
    pclose(pipe);
    return result;
}

int main() {
    std::string output = execute_command("./a.out");
    std::cout << output;
    return 0;
}
